INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f59ed63b-06f0-4235-a4dc-00b323f73270',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vyper Smart Contract Upgrade Patterns with Proxy Contracts$escape$,
  $escape$Vyper's proxy contract pattern enables seamless upgrades to smart contracts without affecting their storage. This is achieved by separating the logic and storage into two separate contracts. The proxy contract acts as an entry point, delegating calls to the logic contract. To implement this pattern, define an interface for the logic contract using the @external decorator, then create a proxy contract that inherits from the interface. The proxy contract's constructor initializes the logic contract address. When upgrading the logic contract, simply deploy a new logic contract and update the proxy contract's logic contract address.$escape$,
  $escape$contract LogicContract:
    @external
    def foo() -> int: ...

class ProxyContract(LogicContract):
    def __init__(logic_contract_address: address):
        self.logic_contract = logic_contract_address$escape$,
  $escape$vyper$escape$,
